package ir.tahamohamadi.skill; import ir.tahamohamadi.common.domain.LanguageCode; import ir.tahamohamadi.common.persistence.AuditedSoftDeletableEntity; import jakarta.persistence.*; import lombok.*;
@Entity @Table(name="skill_category_translation") @Getter @NoArgsConstructor(access=AccessLevel.PROTECTED) public class SkillCategoryTranslation extends AuditedSoftDeletableEntity { @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="skill_category_id",nullable=false) private SkillCategory category; @Enumerated(EnumType.STRING) @Column(name="language_code",nullable=false,length=2) private LanguageCode languageCode; @Column(nullable=false) private String name; @Column(columnDefinition="text") private String description; private SkillCategoryTranslation(java.util.UUID id,SkillCategory category,LanguageCode language,String name,String description,java.time.Instant at){initialize(id,at);this.category=java.util.Objects.requireNonNull(category);languageCode=java.util.Objects.requireNonNull(language);this.name=requireNonBlank(name,"name");this.description=description;} public static SkillCategoryTranslation create(java.util.UUID id,SkillCategory category,LanguageCode language,String name,String description,java.time.Instant at){return new SkillCategoryTranslation(id,category,language,name,description,at);} public void update(String name,String description){this.name=requireNonBlank(name,"name");this.description=description;updatedAt=java.time.Instant.now();} }
